import { DEFAULT_APP_URL, createDebugPage, SWIFTSHADER_LAUNCH_ARGS } from '../support/browser.mjs';

// Use system Chromium with proper swiftshader for headless WebGL rendering.
const { browser, page } = await createDebugPage({
  launchOptions: { args: SWIFTSHADER_LAUNCH_ARGS },
});

const allLogs = [];
page.on('console', msg => allLogs.push(`[${msg.type()}] ${msg.text()}`));
page.on('pageerror', err => allLogs.push(`[PAGE_ERROR] ${err.message}`));

await page.goto(DEFAULT_APP_URL, { waitUntil: 'load', timeout: 30000 });

// Check WebGL immediately
const wg = await page.evaluate(() => {
  const c = document.createElement('canvas');
  const gl2 = c.getContext('webgl2');
  const gl = gl2 || c.getContext('webgl');
  if (!gl) return { ok: false, err: c.getContext('webgl') };
  return { ok: true, vendor: gl.getParameter(gl.VENDOR), renderer: gl.getParameter(gl.RENDERER) };
});
console.log('WebGL:', JSON.stringify(wg));

for (let i = 0; i < 10; i++) {
  await page.waitForTimeout(3000);
  const el = await page.evaluate(() => ({
    canvas: document.querySelectorAll('canvas').length,
    scene: document.querySelectorAll('flt-scene-host').length,
  }));
  console.log(`Wait ${(i+1)*3}s: canvas=${el.canvas} scene=${el.scene}`);
  if (el.canvas > 0) break;
}

console.log('\n=== Console ===');
for (const l of allLogs) console.log(l);

await page.screenshot({ path: '/tmp/navivox-headlessnew.png' });
console.log('Screenshot saved');
await browser.close();--- playwright/debug/accessibility/semantics_test.mjs
import { DEFAULT_APP_URL, createDebugPage } from '../support/browser.mjs';

const { browser, page } = await createDebugPage({
  launchOptions: { args: ['--no-sandbox', '--ignore-gpu-blocklist', '--use-gl=angle', '--use-angle=swiftshader'] },
});

const logs = [];
page.on('console', msg => logs.push(`[${msg.type()}] ${msg.text()}`));
page.on('pageerror', err => logs.push(`[PAGE_ERROR] ${err.message}`));

await page.goto(DEFAULT_APP_URL, { waitUntil: 'load', timeout: 30000 });
await page.waitForTimeout(5000);

// Click the Enable accessibility placeholder via JS (it's at -1,-1 so can't be clicked normally)
await page.evaluate(() => {
  const placeholder = document.querySelector('flt-semantics-placeholder');
  if (placeholder) {
    // Dispatch a click event directly
    placeholder.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
    placeholder.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true, cancelable: true }));
    placeholder.dispatchEvent(new PointerEvent('pointerup', { bubbles: true, cancelable: true }));
  }
});
console.log('Clicked accessibility placeholder');

await page.waitForTimeout(8000);

const state = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const results = [];
  for (const sem of sems) {
    const rect = sem.getBoundingClientRect();
    const role = sem.getAttribute('role') || '';
    const label = sem.getAttribute('aria-label') || '';
    const text = (sem.textContent || '').trim().substring(0, 80);
    if (rect.width > 0 && rect.height > 0) {
      results.push({ role, label, text: text.substring(0, 60), rect });
    }
    if (results.length > 100) break;
  }
  return results;
});

console.log(`\nSemantics elements with size: ${state.length}`);
for (const s of state) {
  console.log(`  role="${s.role}" label="${s.label}" text="${s.text}" rect=${Math.round(s.rect.x)},${Math.round(s.rect.y)} ${Math.round(s.rect.width)}x${Math.round(s.rect.height)}`);
}

// Also get all aria-labeled elements
const allAria = await page.evaluate(() => {
  const all = document.querySelectorAll('[aria-label]');
  return Array.from(all).slice(0, 30).map(el => ({
    tag: el.tagName,
    label: el.getAttribute('aria-label'),
    text: (el.textContent || '').trim().substring(0, 60),
    rect: el.getBoundingClientRect(),
  }));
});
console.log(`\nAll aria-labeled elements: ${allAria.length}`);
for (const a of allAria) {
  if (a.rect.width > 0 && a.rect.height > 0) {
    console.log(`  <${a.tag}> label="${a.label}" text="${a.text}"`);
  }
}

await page.screenshot({ path: '/tmp/navivox-sema-enabled.png' });
console.log('\nScreenshot saved');
await browser.close();--- playwright/debug/chat-input/debug_chat.mjs
// Debug: check chat send button and input
import { openDebugPage } from '../support/browser.mjs';

const { browser, page } = await openDebugPage({
  gotoOptions: { waitUntil: 'load', timeout: 20000 },
  settleMs: 4000,
  enableAccessibility: true,
});

// Navigate to chat fresh (without opening menu)
await page.evaluate(() => {
  const btns = document.querySelectorAll('flt-semantics[role="button"]');
  for (const b of btns) {
    if ((b.textContent || '').includes('Support Triage')) {
      b.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true }));
      b.dispatchEvent(new PointerEvent('pointerup', { bubbles: true }));
      b.dispatchEvent(new MouseEvent('click', { bubbles: true }));
      break;
    }
  }
});
await page.waitForTimeout(3000);
console.log('URL:', page.url());

// Check ALL semantics after navigation
const chatState = await page.evaluate(() => {
  const sems = document.querySelectorAll('flt-semantics');
  const results = [];
  for (const s of sems) {
    const rect = s.getBoundingClientRect();
    if (rect.width > 0 && rect.height > 0) {
      const role = s.getAttribute('role') || '';
      const label = s.getAttribute('aria-label') || '';
      const text = (s.textContent || '').trim().substring(0, 50);
      results.push({ role, label, text, rect: `${Math.round(rect.x)},${Math.round(rect.y)} ${Math.round(rect.width)}x${Math.round(rect.height)}` });
    }
  }
  return results;
});
console.log('Chat semantics:');
for (const s of chatState) {
  if (s.label || s.text) {
    console.log(`  role=${s.role.padEnd(10)} label="${s.label}" text="${s.text}" rect=${s.rect}`);
  }
}

// Check send button specifically
const sendBtn = chatState.find(s => s.label === 'Send' || s.text.includes('Send') || s.text.includes('send'));
console.log('\nSend button:', JSON.stringify(sendBtn));

// Check chat input
const chatInput = await page.evaluate(() => {
  const inputs = document.querySelectorAll('input');
  return Array.from(inputs).map(i => ({
    'aria-label': i.getAttribute('aria-label'),
    type: i.getAttribute('type'),
    value: i.value,
    rect: i.getBoundingClientRect(),
  })).filter(i => i.rect.width > 0);
});
console.log('Chat inputs:', JSON.stringify(chatInput, null, 2));

await browser.close();--- playwright/debug/chat-input/debug_textbox.mjs
// Debug: find the chat textbox element
import { openDebugPage } from '../support/browser.mjs';

const { browser, page } = await openDebugPage({
  gotoOptions: { waitUntil: 'load', timeout: 20000 },
  settleMs: 4000,
  enableAccessibility: true,
});

// Navigate to chat
await page.evaluate(() => {
  const btns = document.querySelectorAll('flt-semantics[role="button"]');
  for (const b of btns) {
    if ((b.textContent || '').includes('Support Triage')) {
      b.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true }));
      b.dispatchEvent(new PointerEvent('pointerup', { bubbles: true }));
      b.dispatchEvent(new MouseEvent('click', { bubbles: true }));
      break;
    }
  }
});
await page.waitForTimeout(3000);

// Find ALL elements with roles
const allRoles = await page.evaluate(() => {
  const all = document.querySelectorAll('*');
  const roles = new Set();
  for (const el of all) {
    const r = el.getAttribute('role');
    if (r) roles.add(r);
  }
  return Array.from(roles);
});
console.log('All roles:', allRoles);

// Find elements with textbox role
const textboxes = await page.evaluate(() => {
  const tbs = document.querySelectorAll('[role="textbox"], [role="textbox"] *, input, textarea, [contenteditable]');
  const results = [];
  for (const tb of tbs) {
    const rect = tb.getBoundingClientRect();
    const ariaLabel = tb.getAttribute('aria-label') || '';
    const text = (tb.textContent || '').trim().substring(0, 40);
    results.push({ tag: tb.tagName, ariaLabel, text, rect: `${Math.round(rect.x)},${Math.round(rect.y)} ${Math.round(rect.width)}x${Math.round(rect.height)}`, visible: rect.width > 0 && rect.height > 0 });
  }
  return results;
});
console.log('\nTextboxes found:');
for (const tb of textboxes) {
  if (tb.visible) console.log(`  <${tb.tag}> label="${tb.ariaLabel}" text="${tb.text}" rect=${tb.rect}`);
}

// Find elements with contenteditable (Flutter uses them for text input)
const editable = await page.evaluate(() => {
  const eds = document.querySelectorAll('[contenteditable="true"], [contenteditable=""]');
  return Array.from(eds).map(e => ({
    tag: e.tagName,
    label: e.getAttribute('aria-label'),
    text: (e.textContent || '').trim().substring(0, 40),
    rect: e.getBoundingClientRect(),
  }));
});
console.log('\nContenteditable:', JSON.stringify(editable));

// Full search for "Message Gormes" text
const msgGormes = await page.evaluate(() => {
  const all = document.querySelectorAll('*');
  for (const el of all) {
    const label = el.getAttribute('aria-label') || '';
    if (label.includes('Message Gormes')) {
      return { tag: el.tagName, label, role: el.getAttribute('role'), rect: el.getBoundingClientRect(), outer: el.outerHTML?.substring(0, 200) };
    }
  }
  return null;
});
console.log('\nMessage Gormes element:', JSON.stringify(msgGormes, null, 2));

await browser.close();--- playwright/debug/chat-input/input_test.mjs
import { openDebugPage } from '../support/browser.mjs';

const { browser, page } = await openDebugPage({
  gotoOptions: { waitUntil: 'load', timeout: 30000 },
  settleMs: 5000,
  enableAccessibility: true,
  accessibilitySettleMs: 4000,
});

// Check what flt-semantics elements have text-fields with labels we need
const semanticsInfo = await page.evaluate(() => {
  const all = document.querySelectorAll('flt-semantics');
  return Array.from(all).map(s => ({
    label: s.getAttribute('aria-label'),
    role: s.getAttribute('role'),
    'data-role': s.getAttribute('data-semantics-role'),
    childInput: s.querySelector('input')?.getAttribute('aria-label'),
    rect: s.getBoundingClientRect(),
  })).filter(s => s.rect.width > 0);
});
console.log('flt-semantics elements:');
for (const s of semanticsInfo) {
  console.log(`  label="${s.label}" role="${s.role}" data-role="${s['data-role']}" child="${s.childInput}"`);
}

// Try clicking the flt-semantics that contains the address input
const addrSemantics = page.locator('flt-semantics').filter({ has: page.locator('input[aria-label="Gateway address field"]') });
console.log('Address semantics count:', await addrSemantics.count());
if (await addrSemantics.count() > 0) {
  await addrSemantics.first().click({ force: true });
  await page.waitForTimeout(1000);
  await page.keyboard.type('192.168.1.1');
  await page.waitForTimeout(1000);
}

// Check what the input value is
const val1 = await page.evaluate(() => {
  const input = document.querySelector('input[aria-label="Gateway address field"]');
  return input ? { value: input.value, disabled: input.disabled } : null;
});
console.log('After keyboard type:', JSON.stringify(val1));

// Try using evaluate to set value via Flutter's internal mechanism
await page.evaluate(() => {
  const input = document.querySelector('input[aria-label="Gateway address field"]');
  if (input) {
    const nativeInputValueSetter = Object.getOwnPropertyDescriptor(
      window.HTMLInputElement.prototype, 'value'
    )?.set;
    nativeInputValueSetter?.call(input, '10.0.0.1');
    input.dispatchEvent(new Event('input', { bubbles: true }));
    input.dispatchEvent(new Event('change', { bubbles: true }));
  }
});
await page.waitForTimeout(1000);

const val2 = await page.evaluate(() => {
  const input = document.querySelector('input[aria-label="Gateway address field"]');
  return input ? input.value : null;
});
console.log('After native value setter:', val2);

await browser.close();--- playwright/debug/chat-input/investigate_blockers.mjs
// Investigate: 1) Nav rail semantics 2) Long-press via gesture 3) Keyboard text entry
import { DEFAULT_APP_URL, enableFlutterAccessibility, openDebugPage } from '../support/browser.mjs';

const { browser, page } = await openDebugPage({
  gotoOptions: { timeout: 20000 },
  settleMs: 2000,
  enableAccessibility: true,
  accessibilitySettleMs: 2000,
});

async function a11y(p) {
  await enableFlutterAccessibility(p, { settleMs: 2000 });
}

// 1. DEEP NAV RAIL PROBE: check for ANY elements with nav-related text at left
console.log('=== 1. NAV RAIL INVESTIGATION ===');
const navCandidates = await page.evaluate(() => {
  const searchWords = ['Chats', 'Servers', 'Agents', 'Memory', 'Config', 'Settings', 'chat_bubble', 'dns', 'smart_toy', 'psychology', 'keyboard_voice'];
  const all = document.querySelectorAll('*');
  const found = [];
  for (const el of all) {
    const t = (el.textContent||'').trim();
    const label = el.getAttribute('aria-label')||'';
    const rect = el.getBoundingClientRect();
    const role = el.getAttribute('role')||'';
    const cls = (el.className||'').substring(0,40);
    for (const w of searchWords) {
      if ((t.includes(w) || label.includes(w)) && rect.width > 0) {
        found.push({tag: el.tagName, role, cls, text: t.substring(0,30), label, x:Math.round(rect.x), y:Math.round(rect.y)});
        break;
      }
    }
  }
  return found.slice(0,40);
});
console.log('Nav-related elements:', navCandidates.length);
for (const n of navCandidates) console.log(`  <${n.tag}> role="${n.role}" cls="${n.cls}" text="${n.text}" label="${n.label}" at ${n.x},${n.y}`);

// Check if NavigationRail exists at all via class names
const railEls = await page.evaluate(() => {
  const all = document.querySelectorAll('*');
  return Array.from(all).filter(e => {
    const c = e.className || '';
    const t = (e.textContent||'').trim();
    const r = e.getBoundingClientRect();
    return (typeof c === 'string' && (c.includes('rail') || c.includes('nav'))) && r.width > 0;
  }).slice(0,10).map(e => ({tag: e.tagName, cls: (e.className||'').substring(0,40), rect: e.getBoundingClientRect()}));
});
console.log('\nRail/nav class elements:', railEls.length);
for (const r of railEls) console.log(`  <${r.tag}> class="${r.cls}" at ${Math.round(r.rect.x)},${Math.round(r.rect.y)} ${Math.round(r.rect.width)}x${Math.round(r.rect.height)}`);

// 2. LONG PRESS: try pointerdown hold for 1s then pointerup
console.log('\n=== 2. LONG PRESS TEST ===');
// Navigate to profile contacts first
await page.goto(DEFAULT_APP_URL, { timeout: 15000 });
await page.waitForTimeout(2000); await a11y(page);

const lpResult = await page.evaluate(() => {
  return new Promise((resolve) => {
    const btns = document.querySelectorAll('flt-semantics[role="button"]');
    for (const b of btns) {
      if ((b.textContent||'').includes('Support Triage')) {
        const rect = b.getBoundingClientRect();
        const cx = rect.x + rect.width/2;
        const cy = rect.y + rect.height/2;

        // Track what appears
        b.dispatchEvent(new PointerEvent('pointerdown', {bubbles:true, clientX:cx, clientY:cy}));

        // Hold for 1200ms then release
        setTimeout(() => {
          b.dispatchEvent(new PointerEvent('pointerup', {bubbles:true, clientX:cx, clientY:cy}));

          // Check for detail sheet (new text appearing)
          const sems = document.querySelectorAll('flt-semantics');
          const newText = [];
          for (const s of sems) {
            const t = (s.textContent||'').trim();
            if (t && t.length > 10 && !t.includes('Navivox') && !t.includes('Search profiles')) {
              newText.push(t.substring(0,60));
            }
          }
          resolve([...new Set(newText)].slice(0,10));
        }, 1200);
        return;
      }
    }
    resolve(['button not found']);
  });
});
console.log('After long press:');
for (const t of lpResult) console.log(`  "${t}"`);

// 3. KEYBOARD TEXT ENTRY: try clicking semantics overlay then keyboard.type
console.log('\n=== 3. TEXT ENTRY VIA KEYBOARD ===');
// Navigate to Support Triage chat
const clicked = await page.evaluate(() => {
  const btns = document.querySelectorAll('flt-semantics[role="button"]');
  for (const b of btns) {
    if ((b.textContent||'').includes('Support Triage')) {
      b.dispatchEvent(new PointerEvent('pointerdown',{bubbles:true}));
      b.dispatchEvent(new PointerEvent('pointerup',{bubbles:true}));
      b.dispatchEvent(new MouseEvent('click',{bubbles:true}));
      return true;
    }
  }
  return false;
});
await page.waitForTimeout(3000);
console.log('At chat:', page.url());

// Find the textarea semantics parent
const semParent = await page.evaluate(() => {
  const ta = document.querySelector('textarea[aria-label="Message Gormes"]');
  if (!ta) return null;
  const parent = ta.closest('flt-semantics');
  if (!parent) return {tag: ta.tagName, rect: ta.getBoundingClientRect()};
  return {tag: parent.tagName, rect: parent.getBoundingClientRect(), role: parent.getAttribute('role')};
});
console.log('Textarea container:', JSON.stringify(semParent));

// Click the semantics parent to focus
if (semParent) {
  await page.mouse.click(semParent.rect.x + 10, semParent.rect.y + 10);
  await page.waitForTimeout(500);

  // Try keyboard input
  await page.keyboard.type('keyboard typed hello');
  await page.waitForTimeout(500);

  // Check if value was transmitted
  const val = await page.evaluate(() => {
    const ta = document.querySelector('textarea[aria-label="Message Gormes"]');
    return ta ? ta.value : null;
  });
  console.log('Textarea value after keyboard:', val);

  // Also check by trying to click the semantics and then type
  // Try clicking the flt-semantics directly
  await page.evaluate(() => {
    const ta = document.querySelector('textarea[aria-label="Message Gormes"]');
    const sem = ta?.closest('flt-semantics');
    if (sem) {
      sem.dispatchEvent(new PointerEvent('pointerdown',{bubbles:true}));
      sem.dispatchEvent(new PointerEvent('pointerup',{bubbles:true}));
      sem.dispatchEvent(new MouseEvent('click',{bubbles:true}));
    }
  });
  await page.waitForTimeout(500);
  await page.keyboard.type(' more text');
  await page.waitForTimeout(500);

  const val2 = await page.evaluate(() => {
    const ta = document.querySelector('textarea[aria-label="Message Gormes"]');
    return ta ? ta.value : null;
  });
  console.log('Textarea value after 2nd attempt:', val2);

  // Now try to click the send button (last empty button)
  await page.evaluate(() => {
    const btns = document.querySelectorAll('flt-semantics[role="button"]');
    const b = btns[btns.length - 1]; // Send button is last
    if (b) {
      b.dispatchEvent(new PointerEvent('pointerdown',{bubbles:true}));
      b.dispatchEvent(new PointerEvent('pointerup',{bubbles:true}));
      b.dispatchEvent(new MouseEvent('click',{bubbles:true}));
    }
  });
  await page.waitForTimeout(2000);

  const texts = await page.evaluate(() => {
    const sems = document.querySelectorAll('flt-semantics');
    return Array.from(sems).slice(0,20).map(s => (s.textContent||'').trim().substring(0,60)).filter(t => t);
  });
  console.log('Texts after send:', [...new Set(texts)].slice(0,10));
}

await page.screenshot({path:'/tmp/navivox-blockers-test.png'});
await browser.close();--- playwright/debug/chat-input/test_keyboard.mjs
// Test keyboard text entry on chat textarea
import { enableFlutterAccessibility, openDebugPage } from '../support/browser.mjs';

const { browser, page } = await openDebugPage({
  gotoOptions: { timeout: 20000 },
  launchOptions: { args: ['--no-sandbox'] },
  settleMs: 2000,
  enableAccessibility: true,
  accessibilitySettleMs: 2000,
});

async function a11y(p) {
  await enableFlutterAccessibility(p, { settleMs: 2000 });
}

// Navigate to Support Triage chat
await page.evaluate(() => {
  const b = [...document.querySelectorAll('flt-semantics[role="button"]')].find(b => (b.textContent||'').includes('Support Triage'));
  if (b) { b.dispatchEvent(new PointerEvent('pointerdown',{bubbles:true})); b.dispatchEvent(new PointerEvent('pointerup',{bubbles:true})); b.dispatchEvent(new MouseEvent('click',{bubbles:true})); }
});
await page.waitForTimeout(3000);
console.log('URL:', page.url());

// 2. Find the chat input
const inputInfo = await page.evaluate(() => {
  const ta = document.querySelector('textarea[aria-label="Message Gormes"]');
  if (!ta) return {found: false, allTextareas: document.querySelectorAll('textarea').length};
  const rect = ta.getBoundingClientRect();
  const sem = ta.closest('flt-semantics');
  return {
    found: true, 
    tag: ta.tagName, 
    disabled: ta.disabled,
    rect: {x: Math.round(rect.x), y: Math.round(rect.y), w: Math.round(rect.width), h: Math.round(rect.height)},
    semRect: sem ? {x: Math.round(sem.getBoundingClientRect().x), y: Math.round(sem.getBoundingClientRect().y), w: Math.round(sem.getBoundingClientRect().width), h: Math.round(sem.getBoundingClientRect().height)} : null
  };
});
console.log('Input:', JSON.stringify(inputInfo, null, 2));

if (inputInfo.found) {
  // 3. Click at the textarea position (not the disabled element, but the region)
  await page.mouse.click(inputInfo.rect.x + 10, inputInfo.rect.y + 10);
  await page.waitForTimeout(500);

  // 4. Press keys and see if they get typed
  await page.keyboard.type('hello from keyboard');
  await page.waitForTimeout(500);

  // 5. Check value
  const val1 = await page.evaluate(() => {
